para.programlisting:
# Web3 Authentication Route
route[auth_web3] {
    # Check if request has credentials
    if (!has_credentials("$fd")) {
        # No credentials - send challenge
        www_challenge("$fd", "0");
        exit;
    }

    # Authenticate using Web3 (same function name as before!)
    # But now it calls blockchain instead of checking password
    if (!pv_www_authenticate("$fd", "0")) {
        switch ($retcode) {
            case -1:
                xlog("L_INFO", "Web3 Auth: No credentials provided\n");
                www_challenge("$fd", "0");
                break;
            case -2:
                xlog("L_INFO", "Web3 Auth: Invalid credentials\n");
                www_challenge("$fd", "16"); # stale=true
                break;
            case -3:
                xlog("L_INFO", "Web3 Auth: Stale nonce\n");
                www_challenge("$fd", "16"); # stale=true
                break;
            default:
                xlog("L_ERR", "Web3 Auth: Authentication error\n");
                sl_send_reply("500", "Server Internal Error");
        }
        exit;
    }

    # Authentication successful!
    xlog("L_INFO", "Web3 Auth: User $fU authenticated via blockchain\n");

    # For REGISTER, save location
    if (is_method("REGISTER")) {
        save("location");
    }
}
